// =====================================================
// 2. Cloudflare Worker 메인
// =====================================================
export default {
  async fetch(request, env, ctx) {
    try {
      const AUTH_KEY = env.AUTH_KEY;

      if (!AUTH_KEY) {
        return kakaoText(
          "기상청 인증키가 설정되지 않았습니다.\n" +
          "Cloudflare Worker secret에서 AUTH_KEY를 확인해 주세요."
        );
      }

      let utterance = "";

      try {
        const body = await request.json();
        utterance = getUserText(body);
      } catch (error) {
        return kakaoText(
          "요청 내용을 읽지 못했습니다.\n" +
          "오류: " + error.message
        );
      }

      const region = findRegion(utterance);

      if (!region) {
        return kakaoText("지역명을 찾을 수 없습니다.");
      }

      if (region.ambiguous) {
        const names = region.candidates
          .map(function (r) {
            return "- " + regionName(r);
          })
          .join("\n");

        return kakaoText(
          "같은 이름의 지역이 여러 곳 있습니다.\n" +
          "시도 또는 시군구를 함께 입력해 주세요.\n\n" +
          names
        );
      }

      const weatherText = await getWeatherText(region, AUTH_KEY);

      return kakaoText(weatherText);

    } catch (error) {
      return kakaoText(
        "Worker 실행 중 오류가 발생했습니다.\n\n" +
        "오류 내용: " + error.message
      );
    }
  }
};


// =====================================================
// 3. 사용자 입력문 추출
// =====================================================
function getUserText(body) {
  const fromUtterance = body.userRequest?.utterance;

  const fromParams =
    body.action?.params?.지역 ||
    body.action?.params?.region ||
    body.action?.params?.location ||
    body.action?.params?.utterance;

  const fromDetailParams =
    body.action?.detailParams?.지역?.origin ||
    body.action?.detailParams?.region?.origin ||
    body.action?.detailParams?.location?.origin;

  return String(
    fromUtterance ||
    fromParams ||
    fromDetailParams ||
    ""
  ).trim();
}


// =====================================================
// 4. 카카오 응답 생성
// =====================================================
function kakaoText(text) {
  const response = {
    version: "2.0",
    template: {
      outputs: [
        {
          simpleText: {
            text: text
          }
        }
      ]
    }
  };

  return new Response(JSON.stringify(response), {
    status: 200,
    headers: {
      "Content-Type": "application/json; charset=utf-8"
    }
  });
}


// =====================================================
// 5. 지역명 출력용
// =====================================================
function regionName(region) {
  const sido = region.sido || "";
  const sgg = region.sgg || "";
  const emd = region.emd || "";

  return [sido, sgg, emd]
    .filter(function (x) {
      return x && String(x).trim() !== "";
    })
    .join(" ");
}


// =====================================================
// 6. 지역명 정규화
// =====================================================
function normalizeText(text) {
  return String(text || "")
    .replace(/\s/g, "")

    // 긴 명칭 먼저
    .replace(/전북특별자치도/g, "전북")
    .replace(/강원특별자치도/g, "강원")
    .replace(/제주특별자치도/g, "제주")

    // 일반 도 명칭
    .replace(/전라북도/g, "전북")
    .replace(/전라남도/g, "전남")
    .replace(/경상북도/g, "경북")
    .replace(/경상남도/g, "경남")
    .replace(/충청북도/g, "충북")
    .replace(/충청남도/g, "충남")
    .replace(/강원도/g, "강원")
    .replace(/제주도/g, "제주")

    // 광역단위 접미어 제거
    .replace(/특별자치도/g, "")
    .replace(/특별자치시/g, "")
    .replace(/특별시/g, "")
    .replace(/광역시/g, "")
    .trim();
}


// =====================================================
// 7. 날씨 조회와 무관한 표현 제거
// 예: "달서구 날씨 알려줘" → "달서구"
// =====================================================
function normalizePlaceQuery(text) {
  return normalizeText(text)
    .replace(/날씨/g, "")
    .replace(/알려줘/g, "")
    .replace(/조회/g, "")
    .replace(/예보/g, "")
    .replace(/정보/g, "")
    .replace(/오늘/g, "")
    .replace(/내일/g, "")
    .replace(/현재/g, "")
    .trim();
}


// =====================================================
// 8. 숫자형 행정동 표현 보정
// 예: 연수1동 → 연수동
// 예: 송천제2동 → 송천동
// =====================================================
function normalizeDongVariant(text) {
  return String(text || "")
    .replace(/([가-힣]+?)(?:제)?\d+동/g, "$1동");
}


function normalizeDongVariantForSearch(originalText) {
  return String(originalText || "")
    .split(/\s+/)
    .map(function (x) {
      const original = normalizeText(x);
      const converted = original.replace(/([가-힣]+?)(?:제)?\d+동/g, "$1동");

      // 실제로 숫자형 행정동이 변환된 경우만 반환
      // 예: 연수1동 → 연수동
      // 예: 송천동 → 반환하지 않음
      if (original !== converted) {
        return converted;
      }

      return "";
    })
    .filter(function (x) {
      return x !== "";
    });
}


// =====================================================
// 법정동 가지번 표현 단순화
// 예: 송천동1가 → 송천동
// 예: 송천동2가 → 송천동
// 예: 신문로2가 → 신문로
// =====================================================
function simplifyLegalDongName(name) {
  return normalizeText(name)
    .replace(/(\d+가)$/g, "")
    .replace(/제\d+가$/g, "");
}


// =====================================================
// 9. 시군구 정확 매칭
// - 달서구 입력 시 서구가 같이 잡히는 문제 방지
// - 고양시 덕양구, 전주시 덕진구 같은 복합 시군구 대응
// =====================================================
function isExactSggMatch(originalText, sido, sgg) {
  const cleanPlaceText = normalizePlaceQuery(originalText);
  const cleanSido = normalizeText(sido);
  const cleanSgg = normalizeText(sgg);

  if (!cleanSgg) {
    return false;
  }

  const tokens = String(originalText || "")
    .split(/\s+/)
    .map(function (x) {
      return normalizePlaceQuery(x);
    })
    .filter(function (x) {
      return x !== "";
    });

  // 시군구 접미어 제거형
  // 예: 동해시 → 동해, 평창군 → 평창
  const cleanSggShort = cleanSgg.replace(/(시|군|구)$/g, "");

  // 예: "동해시"
  if (cleanPlaceText === cleanSgg) {
    return true;
  }

  // 예: "동해"
  // 단, 너무 짧은 지역명 오인식 방지를 위해 2글자 이상만 허용
  if (cleanSggShort.length >= 2 && cleanPlaceText === cleanSggShort) {
    return true;
  }

  // 예: "강원도 동해시", "강원 동해시", "강원특별자치도 동해시"
  if (cleanSido && cleanPlaceText === cleanSido + cleanSgg) {
    return true;
  }

  // 예: "강원 동해"
  if (
    cleanSido &&
    cleanSggShort.length >= 2 &&
    cleanPlaceText === cleanSido + cleanSggShort
  ) {
    return true;
  }

  // 예: ["강원", "동해시"]
  if (tokens.includes(cleanSgg)) {
    return true;
  }

  // 예: ["강원", "동해"]
  if (cleanSggShort.length >= 2 && tokens.includes(cleanSggShort)) {
    return true;
  }

  // 복합 시군구 대응
  // 예: 고양시 덕양구, 전주시 덕진구
  const sggTokens = getSggExactTokens(sgg);

  const majorParts = sggTokens.filter(function (x) {
    return x !== cleanSgg;
  });

  if (majorParts.length >= 2) {
    const allPartsMatched = majorParts.every(function (part) {
      return tokens.includes(part) || cleanPlaceText.includes(part);
    });

    if (allPartsMatched) {
      return true;
    }
  }

  // 구 이름만 입력한 경우
  // 예: 덕양구, 덕진구, 일산동구
  for (const part of majorParts) {
    if (part.endsWith("구") && tokens.includes(part)) {
      return true;
    }

    if (part.endsWith("구") && cleanPlaceText === part) {
      return true;
    }
  }

  return false;
}


// =====================================================
// 10. 시군구 토큰 생성
// 예: 고양시 덕양구 → ["고양시덕양구", "고양시", "덕양구"]
// =====================================================
function getSggExactTokens(sgg) {
  const clean = normalizeText(sgg);

  if (!clean) {
    return [];
  }

  const tokens = new Set();
  tokens.add(clean);

  const parts = clean.match(/[가-힣]+?(시|군|구)/g);

  if (parts) {
    for (const part of parts) {
      tokens.add(part);
    }
  }

  return Array.from(tokens);
}


// =====================================================
// 11. region_list에 들어간 sgg_aliases 정확 매칭
// 예: REGION_LIST의 sgg는 고양시지만 sgg_aliases에 덕양구가 있으면 매칭
// =====================================================
function isExactSggAliasMatch(originalText, alias) {
  const cleanPlaceText = normalizePlaceQuery(originalText);
  const cleanAlias = normalizeText(alias);

  if (!cleanAlias) {
    return false;
  }

  const tokens = String(originalText || "")
    .split(/\s+/)
    .map(function (x) {
      return normalizePlaceQuery(x);
    })
    .filter(function (x) {
      return x !== "";
    });

  // 예: "덕양구"
  if (cleanPlaceText === cleanAlias) {
    return true;
  }

  // 예: "고양시 덕양구 날씨"
  if (tokens.includes(cleanAlias)) {
    return true;
  }

  // 중요:
  // cleanPlaceText.endsWith(cleanAlias)는 사용하지 않음
  // 예: "강남구".endsWith("남구") = true가 되어 포항시 남구로 오인식됨

  return false;
}


// =====================================================
// 단독 구 이름 입력 여부 확인
// 예: 남구, 동구, 서구, 북구, 중구
// =====================================================
function isStandaloneGuName(text) {
  const cleanPlaceText = normalizePlaceQuery(text);

  const standaloneGuNames = [
    "중구",
    "동구",
    "서구",
    "남구",
    "북구"
  ];

  return standaloneGuNames.includes(cleanPlaceText);
}


// =====================================================
// 단독 구 이름 후보 전체 검색
// 예: 남구 → 부산 남구, 대구 남구, 광주 남구, 울산 남구, 포항시 남구 등
// =====================================================
function findStandaloneGuCandidates(text) {
  const cleanPlaceText = normalizePlaceQuery(text);

  if (!isStandaloneGuName(text)) {
    return null;
  }

  const map = new Map();

  for (const region of REGION_LIST) {
    const sgg = normalizeText(region.sgg);
    const sggTokens = getSggExactTokens(region.sgg);
    const sggAliases = Array.isArray(region.sgg_aliases) ? region.sgg_aliases : [];

    let matched = false;

    // 예: 부산광역시 남구처럼 sgg 자체가 남구인 경우
    if (sgg === cleanPlaceText) {
      matched = true;
    }

    // 예: 포항시 남구처럼 sgg가 복합명인 경우
    if (sggTokens.includes(cleanPlaceText)) {
      matched = true;
    }

    // 예: sgg_aliases에 남구가 들어간 경우
    for (const alias of sggAliases) {
      if (normalizeText(alias) === cleanPlaceText) {
        matched = true;
        break;
      }
    }

    if (!matched) {
      continue;
    }

    const key = [
      region.sido || "",
      region.sgg || "",
      JSON.stringify(region.sgg_aliases || [])
    ].join("|");

    if (!map.has(key)) {
      map.set(key, []);
    }

    map.get(key).push(region);
  }

  const groups = Array.from(map.entries()).map(function ([key, items]) {
    return {
      key: key,
      items: items
    };
  });

  if (groups.length === 0) {
    return null;
  }

  if (groups.length === 1) {
    return makeSggRepresentative(groups[0].items, true);
  }

  return {
    ambiguous: true,
    candidates: groups.slice(0, 8).map(function (g) {
      return makeSggRepresentative(g.items, true);
    })
  };
}


// =====================================================
// 공백 기준 지역 토큰 생성
// 예: "서울 강남구 날씨" → ["서울", "강남구", "날씨"]
// =====================================================
function getPlaceTokens(originalText) {
  return String(originalText || "")
    .split(/\s+/)
    .map(function (x) {
      return normalizePlaceQuery(x);
    })
    .filter(function (x) {
      return x !== "";
    });
}


// =====================================================
// 읍면동 정확 매칭
// 예: 식사동은 식사동만 잡고, 사동은 잡지 않음
// =====================================================
function isExactEmdMatch(originalText, emd) {
  const cleanPlaceText = normalizePlaceQuery(originalText);
  const cleanEmd = normalizeText(emd);
  const tokens = getPlaceTokens(originalText);

  if (!cleanEmd) {
    return false;
  }

  // 입력 전체가 읍면동명과 정확히 같은 경우
  // 예: "식사동"
  if (cleanPlaceText === cleanEmd) {
    return true;
  }

  // 공백 기준 토큰으로 정확히 들어간 경우
  // 예: "경기도 식사동 날씨" → ["경기도", "식사동"]
  if (tokens.includes(cleanEmd)) {
    return true;
  }

  // 중요:
  // endsWith 매칭은 사용하지 않음
  // 예: "경기도식사동".endsWith("사동") = true가 되어 오인식 발생

  return false;
}


// =====================================================
// 읍면동 별칭 정확 매칭
// =====================================================
function isExactEmdAliasMatch(originalText, alias) {
  const cleanPlaceText = normalizePlaceQuery(originalText);
  const cleanAlias = normalizeText(alias);
  const tokens = getPlaceTokens(originalText);

  if (!cleanAlias) {
    return false;
  }

  // 입력 전체가 별칭과 정확히 같은 경우
  if (cleanPlaceText === cleanAlias) {
    return true;
  }

  // 공백 기준 토큰으로 정확히 들어간 경우
  if (tokens.includes(cleanAlias)) {
    return true;
  }

  // endsWith 매칭 금지

  return false;
}


// =====================================================
// 12. 지역명 찾기
// =====================================================
function findRegion(text) {
  const cleanText = normalizeText(text);
  const cleanPlaceText = normalizePlaceQuery(text);
  const tokens = getPlaceTokens(text);
  const dongVariantTokens = normalizeDongVariantForSearch(text);

  // -------------------------------------------------
  // 남구, 동구, 서구, 북구, 중구 단독 입력은
  // 점수 계산 전에 REGION_LIST 전체에서 후보를 먼저 찾음
  // -------------------------------------------------
  const standaloneGuResult = findStandaloneGuCandidates(text);

  if (standaloneGuResult) {
    return standaloneGuResult;
  }

  let bestScore = 0;
  let candidates = [];

  for (const region of REGION_LIST) {
    const sido = normalizeText(region.sido);
    const sgg = normalizeText(region.sgg);
    const emd = normalizeText(region.emd);
    const emdSimple = simplifyLegalDongName(region.emd);

    const aliases = Array.isArray(region.aliases) ? region.aliases : [];
    const sggAliasesFromList = Array.isArray(region.sgg_aliases) ? region.sgg_aliases : [];

    let score = 0;

    // -------------------------------------------------
    // 1. 시도명
    // -------------------------------------------------
    if (sido && (tokens.includes(sido) || cleanPlaceText.startsWith(sido))) {
      score += 10;
    }

    // -------------------------------------------------
    // 2. 시군구 전체명 정확 매칭
    // 예: 전주시, 고양시, 대구 서구, 대구 달서구
    // -------------------------------------------------
    if (isExactSggMatch(text, region.sido, region.sgg)) {
      score += 35;
    }

    // -------------------------------------------------
    // 3. 시군구 별칭 매칭
    // 예: 덕진구, 완산구, 덕양구, 동안구
    // -------------------------------------------------
    for (const alias of sggAliasesFromList) {
      if (alias && isExactSggAliasMatch(text, alias)) {
        score += 40;
        break;
      }
    }

    // -------------------------------------------------
    // 4. 읍면동명 정확 매칭
    // 예: 식사동은 식사동만 잡고, 사동은 잡지 않음
    // -------------------------------------------------
    if (isExactEmdMatch(text, region.emd)) {
      score += 70;
    }

    // -------------------------------------------------
    // 5. 법정동 단순명 매칭
    // 예: 송천동1가, 송천동2가 → 송천동
    // -------------------------------------------------
    if (
      emdSimple &&
      emdSimple !== emd &&
      isExactEmdMatch(text, emdSimple)
    ) {
      score += 70;
    }

    // -------------------------------------------------
    // 6. 숫자형 행정동 대응
    // 예: 연수1동 → 연수동
    // 단, 송천동처럼 원래 숫자가 없는 동명에는 가점 안 붙게
    // normalizeDongVariantForSearch()에서 이미 처리해야 함
    // -------------------------------------------------
    if (emd && dongVariantTokens.includes(emd)) {
      score += 55;
    }

    // -------------------------------------------------
    // 7. 읍면동 별칭
    // aliases에 자기 emd명이 그대로 들어간 경우는 중복 가점 방지
    // -------------------------------------------------
    for (const alias of aliases) {
      const aliasNorm = normalizeText(alias);

      if (!aliasNorm || aliasNorm === emd) {
        continue;
      }

      if (isExactEmdAliasMatch(text, alias)) {
        score += 75;
        break;
      }
    }

    // -------------------------------------------------
    // 최고 점수 후보만 유지
    // -------------------------------------------------
    if (score > bestScore) {
      bestScore = score;
      candidates = [region];
    } else if (score === bestScore && score > 0) {
      candidates.push(region);
    }
  }

  // -------------------------------------------------
  // 매칭 없음
  // -------------------------------------------------
  if (bestScore === 0) {
    return null;
  }

  // -------------------------------------------------
  // 후보가 1개면 바로 반환
  // -------------------------------------------------
  if (candidates.length === 1) {
    return candidates[0];
  }

  // -------------------------------------------------
  // 법정동 단순명 그룹 처리
  // 예:
  // - 전주시 송천동 → 송천동1가 + 송천동2가를 송천동 대표로 처리
  // - 송천동 단독 → 전주 송천동 대표 + 안동 송천동 후보 안내
  // -------------------------------------------------
  const simpleEmdGroups = groupBySimpleEmd(candidates, text);

  if (simpleEmdGroups.length > 0) {
    const simpleReps = simpleEmdGroups.map(function (g) {
      return makeSimpleEmdRepresentative(g.items);
    });

    // 입력명과 정확히 같은 emd 후보
    // 예: 안동시 송천동
    const exactEmdCandidates = candidates.filter(function (r) {
      return isExactEmdMatch(text, r.emd);
    });

    // 시도 또는 시군구가 입력되었는지 확인
    // 예: 전주시 송천동, 전주시 덕진구 송천동
    const hasSpecificAreaInput = candidates.some(function (r) {
      const sidoNorm = normalizeText(r.sido);
      const sggNorm = normalizeText(r.sgg);
      const sggAliasList = Array.isArray(r.sgg_aliases) ? r.sgg_aliases : [];

      const sidoMatched =
        sidoNorm &&
        (tokens.includes(sidoNorm) || cleanPlaceText.startsWith(sidoNorm));

      const sggMatched = isExactSggMatch(text, r.sido, r.sgg);

      const sggAliasMatched = sggAliasList.some(function (alias) {
        return isExactSggAliasMatch(text, alias);
      });

      return sidoMatched || sggMatched || sggAliasMatched;
    });

    // 전주시 송천동처럼 시군구가 명확하면 송천동 대표로 처리
    if (hasSpecificAreaInput && simpleEmdGroups.length === 1) {
      return simpleReps[0];
    }

    // 송천동 단독처럼 정확히 같은 다른 지역이 있으면 후보 안내
    if (exactEmdCandidates.length > 0) {
      return {
        ambiguous: true,
        candidates: simpleReps.concat(exactEmdCandidates).slice(0, 8)
      };
    }

    // 단순명 그룹이 하나뿐이면 대표 처리
    if (simpleEmdGroups.length === 1) {
      return simpleReps[0];
    }

    // 단순명 그룹이 여러 개면 후보 안내
    return {
      ambiguous: true,
      candidates: simpleReps.slice(0, 8)
    };
  }

  // -------------------------------------------------
  // 후보 중 읍면동이 직접 매칭된 게 있는지 확인
  // -------------------------------------------------
  const hasEmdMatch = candidates.some(function (r) {
    return isExactEmdMatch(text, r.emd);
  });

  // -------------------------------------------------
  // 읍면동이 아니라 시군구만 매칭된 경우
  // 예:
  // - 전주시 → 전주시 대표
  // - 전주시 덕진구 → 전주시 덕진구 대표
  // -------------------------------------------------
if (!hasEmdMatch) {
  const hasSggAliasMatch = candidates.some(function (r) {
    const aliasList = Array.isArray(r.sgg_aliases) ? r.sgg_aliases : [];

    return aliasList.some(function (alias) {
      return isExactSggAliasMatch(text, alias);
    });
  });

  const groups = groupBySgg(candidates, hasSggAliasMatch);

  // -------------------------------------------------
  // 남구, 동구, 서구, 북구, 중구 단독 입력은 무조건 후보 안내
  // -------------------------------------------------
  if (isStandaloneGuName(text)) {
    return {
      ambiguous: true,
      candidates: groups.slice(0, 8).map(function (g) {
        return makeSggRepresentative(g.items, hasSggAliasMatch);
      })
    };
  }

  if (groups.length === 1) {
    return makeSggRepresentative(groups[0].items, hasSggAliasMatch);
  }

  return {
    ambiguous: true,
    candidates: groups.slice(0, 8).map(function (g) {
      return makeSggRepresentative(g.items, hasSggAliasMatch);
    })
  };
}

  // -------------------------------------------------
  // 그 외에는 중복 후보 안내
  // -------------------------------------------------
  return {
    ambiguous: true,
    candidates: candidates.slice(0, 8)
  };
}


// =====================================================
// 13. 시군구 후보 그룹화
// - useAliasGroup = false: 전주시 전체를 하나로 묶음
// - useAliasGroup = true : 덕진구/완산구처럼 구 단위 별칭별로 묶음
// =====================================================
function groupBySgg(items, useAliasGroup) {
  const map = new Map();

  for (const r of items) {
    const keyParts = [
      r.sido || "",
      r.sgg || ""
    ];

    if (useAliasGroup) {
      keyParts.push(JSON.stringify(r.sgg_aliases || []));
    }

    const key = keyParts.join("|");

    if (!map.has(key)) {
      map.set(key, []);
    }

    map.get(key).push(r);
  }

  return Array.from(map.entries()).map(function ([key, items]) {
    return {
      key: key,
      items: items
    };
  });
}


// =====================================================
// 법정동 단순명 기준 후보 그룹화
// 예: 송천동1가, 송천동2가 → 송천동 그룹
// =====================================================
function groupBySimpleEmd(items, text) {
  const map = new Map();

  for (const r of items) {
    const emd = normalizeText(r.emd);
    const emdSimple = simplifyLegalDongName(r.emd);

    // 송천동1가 → 송천동처럼 실제 단순화된 경우만 사용
    if (!emdSimple || emdSimple === emd) {
      continue;
    }

    // 사용자가 실제로 송천동이라고 입력한 경우만 사용
    if (!isExactEmdMatch(text, emdSimple)) {
      continue;
    }

    const key = [
      r.sido || "",
      r.sgg || "",
      JSON.stringify(r.sgg_aliases || []),
      emdSimple
    ].join("|");

    if (!map.has(key)) {
      map.set(key, []);
    }

    map.get(key).push(r);
  }

  return Array.from(map.entries()).map(function ([key, items]) {
    return {
      key: key,
      items: items
    };
  });
}


// =====================================================
// 법정동 단순명 대표 격자 생성
// 예: 송천동1가 + 송천동2가 → 송천동 대표 격자
// =====================================================
function makeSimpleEmdRepresentative(items) {
  const first = items[0];

  let sumX = 0;
  let sumY = 0;
  let count = 0;

  for (const r of items) {
    const x = Number(r.nx);
    const y = Number(r.ny);

    if (!isNaN(x) && !isNaN(y)) {
      sumX += x;
      sumY += y;
      count += 1;
    }
  }

  return {
    emd_cd: "",
    sgg_cd: first.sgg_cd || "",
    sido: first.sido || "",
    sgg: getDisplaySggName(first),
    emd: simplifyLegalDongName(first.emd),
    nx: count > 0 ? Math.round(sumX / count) : first.nx,
    ny: count > 0 ? Math.round(sumY / count) : first.ny,
    is_simple_emd_rep: true
  };
}


// =====================================================
// 14. 시군구 대표 격자 생성
// - useAliasDisplay = false: 전주시처럼 원래 sgg 표시
// - useAliasDisplay = true : 전주시 덕진구처럼 별칭 표시
// =====================================================
function makeSggRepresentative(items, useAliasDisplay) {
  const first = items[0];

  let sumX = 0;
  let sumY = 0;
  let count = 0;

  for (const r of items) {
    const x = Number(r.nx);
    const y = Number(r.ny);

    if (!isNaN(x) && !isNaN(y)) {
      sumX += x;
      sumY += y;
      count += 1;
    }
  }

  return {
    emd_cd: "",
    sgg_cd: first.sgg_cd || "",
    sido: first.sido || "",
    sgg: useAliasDisplay ? getDisplaySggName(first) : (first.sgg || ""),
    emd: "",
    nx: count > 0 ? Math.round(sumX / count) : first.nx,
    ny: count > 0 ? Math.round(sumY / count) : first.ny,
    is_sgg_rep: true
  };
}


// =====================================================
// 15. 표시용 시군구명
// - sgg_aliases가 있으면 첫 번째 별칭을 우선 표시
// =====================================================
function getDisplaySggName(region) {
  if (Array.isArray(region.sgg_aliases) && region.sgg_aliases.length > 0) {
    return region.sgg_aliases[0];
  }

  return region.sgg || "";
}


// =====================================================
// fetch 타임아웃 처리
// =====================================================
async function fetchWithTimeout(url, timeoutMs) {
  const controller = new AbortController();

  const timer = setTimeout(function () {
    controller.abort();
  }, timeoutMs);

  try {
    const res = await fetch(url, {
      signal: controller.signal
    });

    return res;

  } catch (error) {
    if (error.name === "AbortError") {
      throw new Error("API 응답 지연으로 타임아웃 발생");
    }

    throw error;

  } finally {
    clearTimeout(timer);
  }
}


// =====================================================
// 16. 기상청 APIHub 날씨 조회
// - 모든 기상요소를 조회하되, 일부 실패해도 전체 응답은 유지
// =====================================================
async function getWeatherText(region, AUTH_KEY) {
  const timeInfo = getApiHubTimeInfo();

  const vars = ["TMP", "POP", "PCP", "SKY", "PTY", "REH", "WSD"];

  const promises = vars.map(async function (varName) {
    try {
      const value = await getApiHubGridValue({
        tmfc: timeInfo.tmfc,
        tmef: timeInfo.tmef,
        varName: varName,
        nx: region.nx,
        ny: region.ny,
        AUTH_KEY: AUTH_KEY
      });

      return {
        varName: varName,
        value: value,
        ok: true,
        error: ""
      };

    } catch (error) {
      console.log(varName + " 조회 실패:", error.message);

      return {
        varName: varName,
        value: null,
        ok: false,
        error: error.message
      };
    }
  });

  const pairs = await Promise.all(promises);

  const result = {};
  const errors = {};

  for (const item of pairs) {
    result[item.varName] = item.value;

    if (!item.ok) {
      errors[item.varName] = item.error;
    }
  }

  return makeAnswer(region, result, timeInfo, errors);
}


// =====================================================
// 17. APIHub 격자값 1개 조회
// =====================================================
async function getApiHubGridValue({ tmfc, tmef, varName, nx, ny, AUTH_KEY }) {
  const url =
    "https://apihub.kma.go.kr/api/typ01/cgi-bin/url/nph-dfs_shrt_grd" +
    "?tmfc=" + encodeURIComponent(tmfc) +
    "&tmef=" + encodeURIComponent(tmef) +
    "&vars=" + encodeURIComponent(varName) +
    "&authKey=" + encodeURIComponent(AUTH_KEY);

  const res = await fetchWithTimeout(url, 2500);

  if (!res.ok) {
    throw new Error(
      varName + " API 호출 실패: HTTP " + res.status +
      " / tmfc=" + tmfc +
      " / tmef=" + tmef
    );
  }

  const text = await res.text();

  if (!text || text.trim() === "") {
    throw new Error(
      varName + " 빈 응답" +
      " / tmfc=" + tmfc +
      " / tmef=" + tmef
    );
  }

  if (
    text.includes("ERROR") ||
    text.includes("error") ||
    text.includes("Invalid") ||
    text.includes("인증")
  ) {
    throw new Error(
      varName + " API 오류 응답: " + text.slice(0, 150)
    );
  }

  const values = parseGridValues(text);
  const expected = 149 * 253;

  if (values.length < expected) {
    throw new Error(
      varName +
      " 격자 개수 부족: " +
      values.length +
      " / 기대 개수: " +
      expected +
      " / 응답 앞부분: " +
      text.slice(0, 120)
    );
  }

  return getValueByGrid(values, nx, ny);
}


// =====================================================
// 18. APIHub 텍스트 격자값 파싱
// =====================================================
function parseGridValues(text) {
  const expected = 149 * 253;

  const matches = text.match(/-?\d+(\.\d+)?/g);

  if (!matches) {
    return [];
  }

  const nums = matches.map(Number);

  // 앞부분에 tmfc, tmef 등 메타 숫자가 섞일 수 있으므로 마지막 expected개 사용
  if (nums.length >= expected) {
    return nums.slice(nums.length - expected);
  }

  return nums;
}


// =====================================================
// 19. nx, ny 위치의 값 추출
// =====================================================
function getValueByGrid(values, nx, ny) {
  const NX_COUNT = 149;

  const xIndex = Number(nx) - 1;
  const yIndex = Number(ny) - 1;

  const index = yIndex * NX_COUNT + xIndex;

  const value = values[index];

  if (value === undefined || value === -99 || value === -99.0) {
    return "-";
  }

  return value;
}


// =====================================================
// 20. tmfc, tmef 산정
// - tmfc: 기상청 고정 발표시각
// - tmef: 현재시각 정시 기준
// =====================================================
function getApiHubTimeInfo() {
  const nowUtc = new Date();

  // UTC → KST
  const nowKst = new Date(nowUtc.getTime() + 9 * 60 * 60 * 1000);

  // 발표자료 반영 지연 고려
  // 14:38에도 14시 발표를 쓰려면 30분 정도가 적당
  const baseKst = new Date(nowKst.getTime());
  baseKst.setUTCMinutes(baseKst.getUTCMinutes() - 30);

  const baseHours = [2, 5, 8, 11, 14, 17, 20, 23];

  const year = baseKst.getUTCFullYear();
  const month = baseKst.getUTCMonth();
  const day = baseKst.getUTCDate();
  const hour = baseKst.getUTCHours();

  let selectedHour = null;

  for (const h of baseHours) {
    if (h <= hour) {
      selectedHour = h;
    }
  }

  const tmfcDate = new Date(Date.UTC(year, month, day, 0, 0, 0));

  // 02시 이전이면 전날 23시 발표 사용
  if (selectedHour === null) {
    tmfcDate.setUTCDate(tmfcDate.getUTCDate() - 1);
    selectedHour = 23;
  }

  tmfcDate.setUTCHours(selectedHour);

  // 예보시각은 현재시각의 정시 기준
  const tmefDate = new Date(Date.UTC(
    nowKst.getUTCFullYear(),
    nowKst.getUTCMonth(),
    nowKst.getUTCDate(),
    nowKst.getUTCHours(),
    0,
    0
  ));

  // 현재시각이 발표시각보다 이르면 발표시각 + 1시간
  if (formatKstHour(tmefDate) <= formatKstHour(tmfcDate)) {
    tmefDate.setTime(tmfcDate.getTime());
    tmefDate.setUTCHours(tmefDate.getUTCHours() + 1);
  }

  return {
    tmfc: formatKstHour(tmfcDate),
    tmef: formatKstHour(tmefDate)
  };
}


// =====================================================
// 21. YYYYMMDDHH 형식 변환
// =====================================================
function formatKstHour(dateObj) {
  const yyyy = dateObj.getUTCFullYear();
  const mm = String(dateObj.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(dateObj.getUTCDate()).padStart(2, "0");
  const hh = String(dateObj.getUTCHours()).padStart(2, "0");

  return `${yyyy}${mm}${dd}${hh}`;
}


// =====================================================
// 22. 화면 표시용 날짜 변환
// =====================================================
function formatDisplayTime(yyyymmddhh) {
  const s = String(yyyymmddhh || "");

  if (s.length < 10) {
    return s;
  }

  return (
    s.slice(0, 4) + "-" +
    s.slice(4, 6) + "-" +
    s.slice(6, 8) + " " +
    s.slice(8, 10) + ":00"
  );
}


// =====================================================
// 23. 코드값 해석
// =====================================================
function skyText(value) {
  const v = String(value).trim();

  const map = {
    "1": "맑음",
    "3": "구름많음",
    "4": "흐림"
  };

  return map[v] || "정보 없음";
}


function ptyText(value) {
  const v = String(value).trim();

  const map = {
    "0": "없음",
    "1": "비",
    "2": "비/눈",
    "3": "눈",
    "4": "소나기",
    "5": "빗방울",
    "6": "빗방울/눈날림",
    "7": "눈날림"
  };

  return map[v] || "정보 없음";
}


// =====================================================
// 24. 값 표시
// =====================================================
function formatValue(value, unit) {
  if (value === undefined || value === null || value === "-" || value === "") {
    return "정보 없음";
  }

  return value + unit;
}


// =====================================================
// 25. 강수량 표시
// =====================================================
function formatPcp(value) {
  const v = String(value ?? "").trim();

  if (v === "" || v === "-") {
    return "정보 없음";
  }

  const n = Number(v);

  if (isNaN(n)) {
    return v;
  }

  if (n <= 0) {
    return "0mm";
  }

  return round1(n) + "mm";
}


// =====================================================
// 26. 계절별 체감온도 산출
// - 여름: 기온 + 습도
// - 겨울: 기온 + 풍속
// - 그 외: 기온과 동일
// =====================================================
function calcSensibleTemp(T, RH, V, tmef) {
  if (
    T === null || T === undefined || T === "-" || Number(T) <= -90 ||
    RH === null || RH === undefined || RH === "-" || Number(RH) <= -90 ||
    V === null || V === undefined || V === "-" || Number(V) <= -90
  ) {
    return "자료 없음";
  }

  T = Number(T);
  RH = Number(RH);
  V = Number(V);

  if (isNaN(T) || isNaN(RH) || isNaN(V)) {
    return "자료 없음";
  }

  const month = getMonthFromYyyymmddhh(tmef);

  // 5~9월은 여름철 체감온도
  if (month >= 5 && month <= 9) {
    return calcSummerHeatIndex(T, RH) + "℃";
  }

  // 10~4월은 겨울철 체감온도
  return calcWinterWindChill(T, V) + "℃";
}


// =====================================================
// 27. 여름철 체감온도
// =====================================================
function calcSummerHeatIndex(T, RH) {
  const HI =
    -8.784695 +
    1.61139411 * T +
    2.338549 * RH -
    0.14611605 * T * RH -
    0.012308094 * T * T -
    0.016424828 * RH * RH +
    0.002211732 * T * T * RH +
    0.00072546 * T * RH * RH -
    0.000003582 * T * T * RH * RH;

  return round1(HI);
}


// =====================================================
// 28. 겨울철 체감온도
// =====================================================
function calcWinterWindChill(T, V) {
  const V_kmh = V * 3.6;

  const WC =
    13.12 +
    0.6215 * T -
    11.37 * Math.pow(V_kmh, 0.16) +
    0.3965 * T * Math.pow(V_kmh, 0.16);

  return round1(WC);
}


// =====================================================
// 29. yyyymmddhh에서 월 추출
// =====================================================
function getMonthFromYyyymmddhh(yyyymmddhh) {
  const s = String(yyyymmddhh || "");

  if (s.length < 6) {
    return 0;
  }

  return Number(s.slice(4, 6));
}


// =====================================================
// 30. 소수점 첫째 자리 반올림
// =====================================================
function round1(value) {
  return Math.round(Number(value) * 10) / 10;
}


// =====================================================
// 31. 최종 응답 문장 생성
// - 모든 기상요소를 항상 표시
// =====================================================
function makeAnswer(region, result, timeInfo, errors = {}) {
  const tmp = result.TMP;
  const pop = result.POP;
  const pcp = result.PCP;
  const sky = result.SKY;
  const pty = result.PTY;
  const reh = result.REH;
  const wsd = result.WSD;

  const sensibleTemp = calcSensibleTemp(tmp, reh, wsd, timeInfo.tmef);

  let title = regionName(region);

  if (region.is_sgg_rep) {
    title = region.sido + " " + region.sgg;
  }

  let text =
    "[" + title + " 날씨]\n\n" +
    "발표시각: " + formatDisplayTime(timeInfo.tmfc) + "\n" +
    "예보시각: " + formatDisplayTime(timeInfo.tmef) + "\n\n" +

    "- ☀️ 하늘상태: " + safeSkyText(sky, errors.SKY) + "\n" +
    "- ☁️ 강수형태: " + safePtyText(pty, errors.PTY) + "\n" +
    "- 🌡️ 기온: " + safeValue(tmp, "℃", errors.TMP) +
    " (체감온도: " + sensibleTemp + ")\n" +
    "- 💧 습도: " + safeValue(reh, "%", errors.REH) +
    " (강수확률: " + safeValue(pop, "%", errors.POP) + ")\n" +
    "- 🌧️ 1시간 예상 강수량: " + safePcpText(pcp, errors.PCP) + "\n" +
    "- 🍃 풍속: " + safeValue(wsd, "m/s", errors.WSD);

  return text;
}


// =====================================================
// 값 안전 출력
// =====================================================
function safeValue(value, unit, errorMessage) {
  if (errorMessage) {
    return "자료 수신 실패";
  }

  if (
    value === null ||
    value === undefined ||
    value === "" ||
    value === "-" ||
    Number(value) <= -90
  ) {
    return "자료 없음";
  }

  return String(value) + unit;
}


// =====================================================
// 하늘상태 안전 출력
// SKY: 1 맑음, 3 구름많음, 4 흐림
// =====================================================
function safeSkyText(value, errorMessage) {
  if (errorMessage) {
    return "자료 수신 실패";
  }

  const code = Number(value);

  if (code === 1) return "맑음";
  if (code === 3) return "구름많음";
  if (code === 4) return "흐림";

  return "자료 없음";
}


// =====================================================
// 강수형태 안전 출력
// PTY: 0 없음, 1 비, 2 비/눈, 3 눈, 4 소나기
// =====================================================
function safePtyText(value, errorMessage) {
  if (errorMessage) {
    return "자료 수신 실패";
  }

  const code = Number(value);

  if (code === 0) return "없음";
  if (code === 1) return "비";
  if (code === 2) return "비 또는 눈";
  if (code === 3) return "눈";
  if (code === 4) return "소나기";

  return "자료 없음";
}


// =====================================================
// 강수량 안전 출력
// PCP는 숫자형으로 오면 mm 처리
// =====================================================
function safePcpText(value, errorMessage) {
  if (errorMessage) {
    return "자료 수신 실패";
  }

  if (
    value === null ||
    value === undefined ||
    value === "" ||
    value === "-" ||
    Number(value) <= -90
  ) {
    return "자료 없음";
  }

  const num = Number(value);

  if (isNaN(num)) {
    return String(value);
  }

  if (num === 0) {
    return "강수없음";
  }

  return String(num) + "mm";
}
